def download_all():
    os.makedirs("images", exist_ok=True)
    
    total   = len(IMAGES)
    done    = 0
    skipped = 0
    failed  = []

    headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Referer":    "https://www.serebii.net/",
        "Accept":     "image/webp,image/apng,image/*,*/*;q=0.8",
    }

    for i, item in enumerate(IMAGES):
        dest = os.path.join("images", item["file"])
        
        # Skip if already downloaded
        if os.path.exists(dest) and os.path.getsize(dest) > 1000:
            skipped += 1
            done += 1
            pct = int(done / total * 40)
            bar = "█" * pct + "░" * (40 - pct)
            sys.stdout.write(f"\r[{bar}] {done}/{total}  (skip: {skipped}, fail: {len(failed)})  ")
            sys.stdout.flush()
            continue

        try:
            req = urllib.request.Request(item["url"], headers=headers)
            with urllib.request.urlopen(req, timeout=15) as resp:
                data = resp.read()
            if len(data) < 500:
                raise ValueError(f"Response too small ({len(data)} bytes) — likely an error page")
            with open(dest, "wb") as f:
                f.write(data)
            done += 1
        except Exception as e:
            failed.append({"file": item["file"], "url": item["url"], "error": str(e)})
            done += 1

        pct = int(done / total * 40)
        bar = "█" * pct + "░" * (40 - pct)
        sys.stdout.write(f"\r[{bar}] {done}/{total}  (skip: {skipped}, fail: {len(failed)})  ")
        sys.stdout.flush()

        # Polite delay to avoid hammering Serebii
        if not os.path.exists(dest) or os.path.getsize(dest) < 1000:
            pass
        else:
            time.sleep(0.25)

    print()
    print()
    print(f"✓ Done!  {done - len(failed) - skipped} downloaded, {skipped} already existed, {len(failed)} failed")

    if failed:
        print()
        print("Failed downloads:")
        for f in failed:
            print(f"  {f['file']}: {f['error']}")
        print()
        print("You can re-run this script — it skips already-downloaded files.")
    else:
        print()
        print("All 213 card images are ready. Open card_tracker.html in your browser!")

if __name__ == "__main__":
    print(f"TCG Card Image Downloader — {len(IMAGES)} images")
    print(f"Saving to: ./images/")
    print()
    download_all()
